import AppIntents
import SwiftUI
import SwiftData
@MainActor func intentModelContainer() -> ModelContainer { let sharedDirectory = FileManager.default.containerURL(forSecurityApplicationGroupIdentifier: "group.com.youmind.islandlink")!; let storeURL = sharedDirectory.appendingPathComponent("IslandLink.sqlite"); let config = ModelConfiguration(url: storeURL); do { return try ModelContainer(for: Person.self, Case.self, Event.self, CaseEvent.self, Tag.self, CasePerson.self, EventPerson.self, EventCase.self, configurations: config) } catch { fatalError("Intent ModelContainer 初始化失败: \(error)") } }
struct QueryTomorrowHearings: AppIntent { static var title: LocalizedStringResource = "查询明天的开庭"; static var description = IntentDescription("查询明天有哪些开庭安排", categoryName: "案件查询", searchKeywords: ["开庭", "明天", "庭审", "查询", "日程"]); static var openAppWhenRun: Bool = false
    @MainActor func perform() async throws -> some ReturnsValue<string> & ProvidesDialog { let container = intentModelContainer(); let context = container.mainContext; let calendar = Calendar.current; let today = calendar.startOfDay(for: Date()); let tomorrow = calendar.date(byAdding: .day, value: 1, to: today)!; let dayAfter = calendar.date(byAdding: .day, value: 1, to: tomorrow)!; let eventDescriptor = FetchDescriptor<event>(predicate: #Predicate { event in (event.statusRaw == "planned" || event.statusRaw == "confirmed") && (event.date != nil) && (event.date! >= tomorrow && event.date! < dayAfter) && (event.eventTypeRaw == "hearing" || event.eventTypeRaw == "开庭") }, sortBy: [SortDescriptor(\.date, order: .forward)]); let hearings = (try? context.fetch(eventDescriptor)) ?? []; let caseEventDescriptor = FetchDescriptor<caseevent>(predicate: #Predicate { ce in !ce.isCompleted && ce.date >= tomorrow && ce.date < dayAfter && (ce.eventTypeRaw == "trial" || ce.eventTypeRaw == "sentencing") }, sortBy: [SortDescriptor(\.date, order: .forward)]); let caseHearings = (try? context.fetch(caseEventDescriptor)) ?? []; if hearings.isEmpty, caseHearings.isEmpty { return .result(value: "明天没有开庭安排，可以放松一下。", dialog: "明天没有开庭安排。") }; var lines: [String] = ["明天共有 \(hearings.count + caseHearings.count) 场开庭："]; for hearing in hearings { if let date = hearing.date { let timeStr = date.formatted(.dateTime.hour().minute()); lines.append("• \(timeStr) \(hearing.title)") } }; for hearing in caseHearings { let timeStr = hearing.date.formatted(.dateTime.hour().minute()); let caseName = hearing.case?.name ?? ""; lines.append("• \(timeStr) \(hearing.title) (\(caseName))") }; let result = lines.joined(separator: "
"); return .result(value: result, dialog: "明天有 \(hearings.count + caseHearings.count) 场开庭。") } }
struct QueryTodayEvents: AppIntent { static var title: LocalizedStringResource = "查询今天的事项"; static var description = IntentDescription("查询今天有哪些待办事项", categoryName: "事项管理", searchKeywords: ["事项", "今天", "待办", "日程"]); static var openAppWhenRun: Bool = false
    @MainActor func perform() async throws -> some ReturnsValue<string> & ProvidesDialog { let container = intentModelContainer(); let context = container.mainContext; let calendar = Calendar.current; let today = calendar.startOfDay(for: Date()); let tomorrow = calendar.date(byAdding: .day, value: 1, to: today)!; let descriptor = FetchDescriptor<event>(predicate: #Predicate { event in (event.statusRaw == "planned" || event.statusRaw == "confirmed") && (event.date != nil) && (event.date! >= today && event.date! < tomorrow) }, sortBy: [SortDescriptor(\.date, order: .forward)]); let events = (try? context.fetch(descriptor)) ?? []; if events.isEmpty { return .result(value: "今天没有待办事项。", dialog: "今天没有待办事项。") }; var lines: [String] = ["今天有 \(events.count) 件事项："]; for event in events { if let date = event.date { let timeStr = event.isAllDay ? "全天" : date.formatted(.dateTime.hour().minute()); lines.append("• \(timeStr) — \(event.title)") } }; let result = lines.joined(separator: "
"); return .result(value: result, dialog: "今天有 \(events.count) 件事项。") } }
struct CreateNewCase: AppIntent { static var title: LocalizedStringResource = "新建案件"; static var description = IntentDescription("通过语音快速新建案件", categoryName: "案件管理"); static var openAppWhenRun: Bool = true; @Parameter(title: "案件名称") var caseName: String; @Parameter(title: "案件类型", default: .civil) var caseType: CaseTypeEnum; @Parameter(title: "案号") var caseNumber: String?; @Parameter(title: "管辖法院") var court: String?; static var parameterSummary: some ParameterSummary { Summary("新建案件「\(\.$caseName)」") { \.$caseType; \.$caseNumber; \.$court } }
    @MainActor func perform() async throws -> some IntentResult & ProvidesDialog { let container = intentModelContainer(); let context = container.mainContext; let newCase = Case(name: caseName, caseType: caseType.toCaseType, caseNumber: caseNumber, court: court); context.insert(newCase); try? context.save(); return .result(dialog: "已新建案件「\(caseName)」。") } }
struct CreateNewEvent: AppIntent { static var title: LocalizedStringResource = "新建事项"; static var description = IntentDescription("通过语音快速新建事项", categoryName: "事项管理"); static var openAppWhenRun: Bool = false; @Parameter(title: "事项标题") var title: String; @Parameter(title: "事项类型", default: .other) var eventType: EventTypeEnum; @Parameter(title: "日期") var date: Date?; static var parameterSummary: some ParameterSummary { Summary("新建事项「\(\.$title)」") { \.$eventType; \.$date } }
    @MainActor func perform() async throws -> some IntentResult & ProvidesDialog { let container = intentModelContainer(); let context = container.mainContext; let newEvent = Event(title: title, eventType: eventType.toEventType, status: .confirmed, date: date); context.insert(newEvent); try? context.save(); if let date = date { let dateStr = date.formatted(.dateTime.month(.abbreviated).day().hour().minute()); return .result(dialog: "已新建事项「\(title)」，定于 \(dateStr)。") }; return .result(dialog: "已新建事项「\(title)」。") } }
struct CreateNewPerson: AppIntent { static var title: LocalizedStringResource = "新建联系人"; static var description = IntentDescription("通过语音快速新建联系人", categoryName: "联系人管理"); static var openAppWhenRun: Bool = false; @Parameter(title: "姓名") var name: String; @Parameter(title: "单位") var org: String?; @Parameter(title: "角色") var role: PersonRoleEnum?; @Parameter(title: "电话") var phone: String?; @Parameter(title: "备注") var notes: String?; static var parameterSummary: some ParameterSummary { Summary("新建联系人「\(\.$name)」") { \.$role; \.$org; \.$phone; \.$notes } }
    @MainActor func perform() async throws -> some IntentResult & ProvidesDialog { let container = intentModelContainer(); let context = container.mainContext; let roleTypes: [PersonRoleType]; if let r = role { roleTypes = [r.toRoleType] } else { roleTypes = [] }; let newPerson = Person(name: name, roleTypes: roleTypes, org: org, phone: phone, notes: notes); context.insert(newPerson); try? context.save(); return .result(dialog: "已新建联系人「\(name)」。") } }
enum CaseTypeEnum: String, AppEnum { case civil = "民事"; case criminal = "刑事"; case administrative = "行政"; case arbitration = "仲裁"; case nonLitigation = "非诉"; static var typeDisplayRepresentation: TypeDisplayRepresentation { "案件类型" }; static var caseDisplayRepresentations: [CaseTypeEnum: DisplayRepresentation] { [.civil: "民事", .criminal: "刑事", .administrative: "行政", .arbitration: "仲裁", .nonLitigation: "非诉"] }; var toCaseType: CaseType { switch self { case .civil: return .civil; case .criminal: return .criminal; case .administrative: return .administrative; case .arbitration: return .arbitration; case .nonLitigation: return .nonLitigation } } }
enum EventTypeEnum: String, AppEnum { case meeting = "会议"; case deadline = "截止日"; case hearing = "开庭"; case filing = "立案/递交"; case research = "调研"; case travel = "出差"; case social = "社交"; case other = "其他"; static var typeDisplayRepresentation: TypeDisplayRepresentation { "事项类型" }; static var caseDisplayRepresentations: [EventTypeEnum: DisplayRepresentation] { [.meeting: "会议", .deadline: "截止日", .hearing: "开庭", .filing: "立案/递交", .research: "调研", .travel: "出差", .social: "社交", .other: "其他"] }; var toEventType: EventType { switch self { case .meeting: return .meeting; case .deadline: return .deadline; case .hearing: return .hearing; case .filing: return .filing; case .research: return .research; case .travel: return .travel; case .social: return .social; case .other: return .other } } }
enum PersonRoleEnum: String, AppEnum { case judge = "法官"; case prosecutor = "检察官"; case lawyer = "律师"; case party = "当事人"; case police = "公安民警"; case witness = "证人"; case clerk = "书记员"; case expert = "鉴定人"; case other = "其他"; static var typeDisplayRepresentation: TypeDisplayRepresentation { "角色" }; static var caseDisplayRepresentations: [PersonRoleEnum: DisplayRepresentation] { [.judge: "法官", .prosecutor: "检察官", .lawyer: "律师", .party: "当事人", .police: "公安民警", .witness: "证人", .clerk: "书记员", .expert: "鉴定人", .other: "其他"] }; var toRoleType: PersonRoleType { switch self { case .judge: return .judge; case .prosecutor: return .prosecutor; case .lawyer: return .lawyer; case .party: return .party; case .police: return .police; case .witness: return .witness; case .clerk: return .clerk; case .expert: return .expert; case .other: return .other } } }
struct IslandLinkShortcuts: AppShortcutsProvider { static var appShortcuts: [AppShortcut] { [AppShortcut(intent: QueryTomorrowHearings(), phrases: ["查一下明天的开庭", "明天开庭有哪些", "明天有什么庭审", "查看明天的开庭安排", "明天开庭情况"], shortTitle: "明天的开庭", systemImageName: "hammer.fill"), AppShortcut(intent: QueryTodayEvents(), phrases: ["查一下今天的事项", "今天有哪些事项", "今天有什么安排", "今天待办事项"], shortTitle: "今天的事项", systemImageName: "calendar.badge.clock"), AppShortcut(intent: CreateNewCase(), phrases: ["新建一个案件叫\(\.$caseName)", "创建一个案件\(\.$caseName)", "新增案件\(\.$caseName)"], shortTitle: "新建案件", systemImageName: "folder.badge.plus"), AppShortcut(intent: CreateNewEvent(), phrases: ["新建一个事项\(\.$title)", "添加事项\(\.$title)", "提醒我\(\.$title)"], shortTitle: "新建事项", systemImageName: "plus.circle.fill"), AppShortcut(intent: CreateNewPerson(), phrases: ["新建联系人\(\.$name)", "在\(\.$name)的联系人里记一笔", "添加联系人\(\.$name)"], shortTitle: "新建联系人", systemImageName: "person.badge.plus")] } }